shape.script:
function getHandles(params) {
    let headWidth = params.headWidth;
    let headLength = params.headLength;
    let lineWidth = Math.min(headWidth,params.lineWidth);
    let end = params.end;
    let start = params.start;
    let dx = end.x-start.x;
    let dy = end.y-start.y;
    let dlen = Math.hypot(dx,dy);
    let nx = dx / dlen;
    let ny = dy / dlen;
    let tailLength = dlen - headLength;
    let cwX = -dy / dlen;
    let cwY = dx / dlen;
    let ccwX = dy / dlen;
    let ccwY = -dx / dlen;
    return {
        s: params.start,
        e: params.end,
        lw: {
            x: start.x + cwX * lineWidth + nx * tailLength/3,
            y: start.y + cwY * lineWidth + ny * tailLength/3,
            axis:[cwX,cwY]
        },
        hw: {
            x: start.x + cwX * headWidth + nx * tailLength,
            y: start.y + cwY * headWidth + ny * tailLength,
            axis:[cwX,cwY]
        },
        hl: {
            x: start.x + ccwX * (lineWidth+headWidth)/2 + nx * tailLength,
            y: start.y + ccwY * (lineWidth+headWidth)/2 + ny * tailLength,
            axis:[-nx,-ny]
        }
    }
}

function getPath(params) {
    let headWidth = params.headWidth;
    let headLength = params.headLength;
    let lineWidth = Math.min(headWidth,params.lineWidth);
    let end = params.end;
    let start = params.start;
    let dx = end.x-start.x;
    let dy = end.y-start.y;
    let dlen = Math.hypot(dx,dy);
    let nx = dx / dlen;
    let ny = dy / dlen;
    let tailLength = dlen - headLength;
    let cwX = -dy / dlen;
    let cwY = dx / dlen;
    let ccwX = dy / dlen;
    let ccwY = -dx / dlen;
    return [
        [start.x + cwX * lineWidth, start.y + cwY * lineWidth],
        [start.x + ccwX * lineWidth, start.y + ccwY * lineWidth],
        [start.x + ccwX * lineWidth + nx * tailLength, start.y + ccwY * lineWidth + ny * tailLength],
        [start.x + ccwX * headWidth + nx * tailLength, start.y + ccwY * headWidth + ny * tailLength],
        [end.x, end.y],
        [start.x + cwX * headWidth + nx * tailLength, start.y + cwY * headWidth + ny * tailLength],
        [start.x + cwX * lineWidth + nx * tailLength, start.y + cwY * lineWidth + ny * tailLength],
        {closed:true}
    ];
}
